import{_ as a,o as s,c as t,a5 as n}from"./chunks/framework.B5tqjWbr.js";const u=JSON.parse('{"title":"概念：UPS 参数访问边界（parameter access boundary）","description":"","frontmatter":{"date":"2026-06-21T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：UPS 参数访问边界（parameter access boundary）","tags":["power-electronics"],"status":"learning","summary":"本页是 `lessons/0034-ups-parameter-access.html` 的源稿和补充资料。它只使用教学参数访问表，不包含公司内部参数访问表、客户项目参数、未公开产品阈值或内部调试命令。"},"headers":[],"relativePath":"content/power/concepts/embedded/ups-parameter-access.md","filePath":"content/power/concepts/embedded/ups-parameter-access.md","lastUpdated":null}'),r={name:"content/power/concepts/embedded/ups-parameter-access.md"};function p(i,e,l,c,o,d){return s(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="概念-ups-参数访问边界-parameter-access-boundary" tabindex="-1">概念：UPS 参数访问边界（parameter access boundary） <a class="header-anchor" href="#概念-ups-参数访问边界-parameter-access-boundary" aria-label="Permalink to &quot;概念：UPS 参数访问边界（parameter access boundary）&quot;">​</a></h1><p>本页是 <code>lessons/0034-ups-parameter-access.html</code> 的源稿和补充资料。它只使用教学参数访问表，不包含公司内部参数访问表、客户项目参数、未公开产品阈值或内部调试命令。</p><h2 id="它是什么" tabindex="-1">它是什么 <a class="header-anchor" href="#它是什么" aria-label="Permalink to &quot;它是什么&quot;">​</a></h2><p>参数访问（parameter access）是通信模块或调试工具读取、写入固件参数的边界层。它决定某个参数是只读（read-only）、可读写（read-write），以及写入值是否通过范围校验（range check）。</p><p>本课只讲一个概念：外部写参数不能直接改 C 变量，必须经过访问策略和范围校验。</p><h2 id="为什么-ups-需要它" tabindex="-1">为什么 UPS 需要它 <a class="header-anchor" href="#为什么-ups-需要它" aria-label="Permalink to &quot;为什么 UPS 需要它&quot;">​</a></h2><p>UPS 的参数会影响保护阈值、控制周期、同步窗口和故障行为。如果外部工具可以随便写这些参数，轻则调试结果混乱，重则破坏保护边界。</p><p>因此参数表（parameter table）之外，还需要参数访问层：它把“参数是什么”“能不能写”“写入范围是多少”“拒绝原因是什么”集中管理。</p><h2 id="物理直觉" tabindex="-1">物理直觉 <a class="header-anchor" href="#物理直觉" aria-label="Permalink to &quot;物理直觉&quot;">​</a></h2><p>参数访问层像设备柜门上的权限标签：有些旋钮只能看不能拧，有些旋钮可以调，但只能在红线范围内调。通信命令只是伸手去调，真正能不能调由参数访问层决定。</p><h2 id="数学形式" tabindex="-1">数学形式 <a class="header-anchor" href="#数学形式" aria-label="Permalink to &quot;数学形式&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>read(parameter_id):</span></span>
<span class="line"><span>    return value, access_policy</span></span>
<span class="line"><span></span></span>
<span class="line"><span>write(parameter_id, requested_value):</span></span>
<span class="line"><span>    if access_policy == READ_ONLY:</span></span>
<span class="line"><span>        return accepted = 0, reject_reason = READ_ONLY</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    if requested_value &lt; min or requested_value &gt; max:</span></span>
<span class="line"><span>        return accepted = 0, reject_reason = OUT_OF_RANGE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    parameter.value = requested_value</span></span>
<span class="line"><span>    return accepted = 1, reject_reason = NONE</span></span></code></pre></div><p>本课使用教学范围 <code>MAINS_UV_THRESHOLD_V = 120..240 V</code>，不代表任何真实产品阈值。</p><h2 id="仿真观察" tabindex="-1">仿真观察 <a class="header-anchor" href="#仿真观察" aria-label="Permalink to &quot;仿真观察&quot;">​</a></h2><p>运行：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\ups_parameter_access.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span></code></pre></div><p>默认生成：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>simulations/results/ups_parameter_access.png</span></span></code></pre></div><p>图中包含参数编号、写入是否接受、拒绝原因和 <code>mains_uv_threshold_v</code> 的值变化。图内参数框说明：<code>CONTROL_ISR_PERIOD_US</code> 是只读，写入被拒绝；<code>MAINS_UV_THRESHOLD_V=90 V</code> 越界被拒绝；<code>MAINS_UV_THRESHOLD_V=170 V</code> 被接受。默认不加 <code>--no-open</code> 时脚本会尝试自动打开图片；打不开时会打印完整路径。</p><h2 id="固件落地" tabindex="-1">固件落地 <a class="header-anchor" href="#固件落地" aria-label="Permalink to &quot;固件落地&quot;">​</a></h2><ul><li><code>UpsParameterId</code>：教学参数编号。</li><li><code>UPS_PARAMETER_MAINS_UV_THRESHOLD_V</code>：市电欠压阈值教学参数，可读写但有范围限制。</li><li><code>UPS_PARAMETER_CONTROL_ISR_PERIOD_US</code>：控制中断周期教学参数，只读。</li><li><code>UpsParameterAccess</code>：访问策略。</li><li><code>UPS_PARAMETER_ACCESS_READ_ONLY</code>：只读。</li><li><code>UPS_PARAMETER_ACCESS_READ_WRITE</code>：可读写。</li><li><code>UpsParameter_Read()</code>：读取参数值和访问策略。</li><li><code>UpsParameter_Write()</code>：执行写入前的只读检查和范围校验。</li><li><code>UpsParameterWriteResult</code>：写入是否接受和拒绝原因（reject reason）。</li></ul><p>真实工程还会涉及掉电保存、参数版本、校验和、默认值恢复、权限、在线修改限制和写 Flash 寿命。本课先训练阅读边界。</p><h2 id="常见误解" tabindex="-1">常见误解 <a class="header-anchor" href="#常见误解" aria-label="Permalink to &quot;常见误解&quot;">​</a></h2><ul><li>错误理解：通信写参数就是给变量赋值。<br> 正确理解：写参数必须经过访问策略、范围校验和安全条件。</li><li>错误理解：只读参数没有必要出现在访问表里。<br> 正确理解：只读参数也要能被外部读取，并明确拒绝写入。</li><li>错误理解：可以把导师给的真实参数范围记到学习仓库。<br> 正确理解：不能记录公司内部参数访问表，只能记录通用组织方式和问题清单。</li></ul><h2 id="验收标准" tabindex="-1">验收标准 <a class="header-anchor" href="#验收标准" aria-label="Permalink to &quot;验收标准&quot;">​</a></h2><ul><li>能运行 <code>python simulations\\python\\ups_parameter_access.py --no-open</code> 并打开 <code>simulations/results/ups_parameter_access.png</code>。</li><li>能解释只读、可读写、范围校验和拒绝原因的区别。</li><li>能解释为什么控制周期这类参数通常不应被普通通信写入。</li><li>能编译并运行 <code>projects/03-ups-c-firmware-skeleton</code>，看到 <code>parameter_access</code> 输出。</li><li>能基于 <code>parameter_access.c -&gt; UpsParameter_Write()</code> 准备导师问题。</li></ul><h2 id="导师问题" tabindex="-1">导师问题 <a class="header-anchor" href="#导师问题" aria-label="Permalink to &quot;导师问题&quot;">​</a></h2><ul><li>我用 <code>parameter_access.c -&gt; UpsParameter_Write()</code> 区分只读、可读写和越界拒绝。真实工程里参数访问表通常还会包含哪些通用字段？</li><li>我用 <code>simulations/results/ups_parameter_access.png</code> 看到越界写入不会改变参数值。真实工程中写入失败时通常会返回拒绝原因、当前值，还是两者都返回？</li><li>我不会记录公司内部参数范围，只想确认阅读方式：看真实工程时，应先看参数定义、访问权限表，还是通信写入入口？</li></ul>`,28)])])}const _=a(r,[["render",p]]);export{u as __pageData,_ as default};
